// src/App.js
import { useNodesState, useEdgesState } from "reactflow";
import { PipelineToolbar } from "./toolbar";
import { PipelineUI } from "./ui";
import FlowCanvas from "./FlowCanvas";

function App() {
  const initialNodes = [
    { id: "1", type: "inputNode", position: { x: 50, y: 50 }, data: {} },
    { id: "2", type: "llmNode", position: { x: 300, y: 50 }, data: {} },
    { id: "3", type: "textNode", position: { x: 50, y: 200 }, data: {} },
    { id: "4", type: "outputNode", position: { x: 300, y: 200 }, data: {} },
    {
      id: "5",
      type: "deleteNode",
      position: { x: 550, y: 125 },
      data: { incoming: null, onDelete: (targetId) => handleDeleteNode(targetId) },
    },
  ];

  const initialEdges = [
    { id: "e1-2", source: "1", target: "2" },
    { id: "e3-2", source: "3", target: "2" },
    { id: "e2-4", source: "2", target: "4" },
    // no hardcoded e5-2 here
  ];

  const [nodes, setNodes, onNodesChange] = useNodesState(initialNodes);
  const [edges, setEdges, onEdgesChange] = useEdgesState(initialEdges);

  const handleDeleteNode = (targetId) => {
    setNodes((nds) => nds.filter((n) => n.id !== targetId));
    setEdges((eds) => eds.filter((e) => e.source !== targetId && e.target !== targetId));
  };

  // ✅ FIX: use updatedEdges instead of stale edges
  const handleEdgesChange = (changes) => {
    const updatedEdges = onEdgesChange(changes);

    setNodes((nds) =>
      nds.map((n) =>
        n.type === "deleteNode"
          ? {
              ...n,
              data: {
                ...n.data,
                incoming: updatedEdges.find((e) => e.target === n.id)?.source || null,
                onDelete: handleDeleteNode,
              },
            }
          : n
      )
    );

    setEdges(updatedEdges);
  };

  return (
    <div>
      <PipelineToolbar />
      <PipelineUI />
      <FlowCanvas
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={handleEdgesChange}
        onConnect={(params) => setEdges((eds) => [...eds, params])}
      />
    </div>
  );
}

export default App;
